#include<bits/stdc++.h>
using namespace std;
vector<int> mp[100010];
int n,k;
int dis[100010],sum[100010],c[100010],f[100010][21],ans[100010];
void dfs(int x,int fa=-1)
{
    for(int i=0;i<=k;i++)
    {
        f[x][i]=c[x];
    }
    for(int i:mp[x])
    {
        if(i!=fa)
        {
            dis[i]=dis[x]+1;
            dfs(i,x);
            for(int j=1;j<=k;j++)
            {
                f[x][j]+=f[i][j-1];
            }
        }
    }
}
void dfs1(int x,int fa=-1)
{
    ans[x]=f[x][k];
    for(int i:mp[x])
    {
        if(i!=fa)
        {
            for(int j=k;j>=2;j--)
            {
                f[i][j]+=f[x][j-1]-f[i][j-2];
            }
            f[i][1]+=c[x];
            dfs1(i,x);
        }
    }
}
int main()
{
    
    scanf("%d%d",&n,&k);
    for(int i=1;i<n;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&c[i]);
    }
    dfs(1);
    dfs1(1);
    for(int i=1;i<=n;i++)
    {
        printf("%d\n",ans[i]);
    }
    return 0;
}
